            'root_tag': root.tag,
            'elements_count': len(root),
            'text_content': ' '.join(root.itertext())
        }

        return jsonify(processed_data)

    except ET.ParseError as e:
        # Handle XML parsing errors
        return jsonify({'error': 'Invalid XML format', 'details': str(e)}), 400
