import os
import sys

# File to track the next note number
NOTE_COUNTER_FILE = "notes_counter.txt"
NOTE_FILES_DIR = "notes"

def initialize_note_counter():
    """Initialize the note counter if the file doesn't exist"""
    if not os.path.exists(NOTE_COUNTER_FILE):
        with open(NOTE_COUNTER_FILE, 'w') as f:
            f.write("1")

def get_next_note_number():
    """Get the next available note number"""
    try:
        with open(NOTE_COUNTER_FILE, 'r') as f:
            return int(f.read())
    except (IOError, ValueError):
        return 1

def save_note_number(number):
    """Save the updated note number"""
    with open(NOTE_COUNTER_FILE, 'w') as f:
        f.write(str(number))

def create_note_file(content):
    """Create a new note file with the current note number"""
    note_number = get_next_note_number()
    filename = os.path.join(NOTE_FILES_DIR, f"note_{note_number}.txt")

    # Create directory if it doesn't exist
    os.makedirs(NOTE_FILES_DIR, exist_ok=True)

    with open(filename, 'w') as f:
        f.write(content)

    save_note_number(note_number + 1)
    return filename

def view_note(filename):
    """View the content of a note file"""
    if not os.path.exists(filename):
        print("Error: Note file not found.")
        return

    with open(filename, 'r') as f:
        print(f"\nNote Content:\n{f.read()}\n")

def delete_note(filename):
    """Delete a note file"""
    if not os.path.exists(filename):
        print("Error: Note file not found.")
        return

    os.remove(filename)
    print("Note deleted successfully.")

def list_notes():
    """List all note files"""
    note_files = [f for f in os.listdir(NOTE_FILES_DIR) if f.startswith("note_")]
    if not note_files:
        print("No notes found.")
        return

    print("\nAvailable notes:")
    for i, filename in enumerate(note_files, 1):
        print(f"{i}. {filename}")

def main():
    """Main application loop"""
    initialize_note_counter()

    while True:
        print("\nNote Taking App")
        print("1. Create note")
        print("2. View notes")
        print("3. Delete note")
        print("4. Exit")

        try:
            choice = int(input("Enter your choice (1-4): "))
        except ValueError:
            print("Please enter a valid number.")
            continue

        if choice == 1:
            content = input("Enter your note content (empty to cancel): ").strip()
            if not content:
                print("Note creation cancelled.")
                continue

            filename = create_note_file(content)
            print(f"Note saved as {filename}")

        elif choice == 2:
            list_notes()
            if not os.listdir(NOTE_FILES_DIR):
                continue

            try:
                note_num = int(input("\nEnter note number to view: "))
                note_files = [f for f in os.listdir(NOTE_FILES_DIR) if f.startswith("note_")]
                selected_file = note_files[note_num - 1]
                view_note(os.path.join(NOTE_FILES_DIR, selected_file))
            except (IndexError, ValueError):
                print("Invalid note number.")

        elif choice == 3:
            list_notes()
            if not os.listdir(NOTE_FILES_DIR):
                continue

            try:
                note_num = int(input("\nEnter note number to delete: "))
                note_files = [f for f in os.listdir(NOTE_FILES_DIR) if f.startswith("note_")]
                selected_file = note_files[note_num - 1]
                delete_note(os.path.join(NOTE_FILES_DIR, selected_file))
